            // ALSO VALID: use FindElements<T> for type-specific search:
            var figures = root.FindElements<FigureElement>(true);
            Console.WriteLine($"Found {figures.Count} figure elements.");
        }
    }

    static void Walk(StructureElement el, int depth)
    {
        string indent = new string(' ', depth * 2);
        Console.WriteLine($"{indent}{el.GetType().Name}: {el.ActualText}");
        foreach (Element child in el.ChildElements)  // ChildElements — NOT Elements
            if (child is StructureElement se) Walk(se, depth + 1);
    }
}

