Basic operation: Encrypt and Decrypt PDF.code:
using System;
using System.IO;
using Aspose.Pdf;

class Program
{
    static void Main()
    {
        const string inputPath     = "input.pdf";
        const string encryptedPath = "encrypted.pdf";
        const string decryptedPath = "decrypted.pdf";
        const string userPassword  = "user123";
        const string ownerPassword = "owner123";

        if (!File.Exists(inputPath)) { Console.Error.WriteLine($"Not found: {inputPath}"); return; }

        try
        {
            using (Document doc = new Document(inputPath))
            {
                Permissions perms = Permissions.PrintDocument | Permissions.ExtractContent;
                doc.Encrypt(userPassword, ownerPassword, perms, CryptoAlgorithm.AESx256);
                doc.Save(encryptedPath);
            }

            using (Document encDoc = new Document(encryptedPath, userPassword))
            {
                encDoc.Decrypt();
                encDoc.Save(decryptedPath);
            }

            Console.WriteLine("Encrypt/decrypt completed.");
        }
        catch (InvalidPasswordException ex) { Console.Error.WriteLine($"Wrong password: {ex.Message}"); }
        catch (Exception ex)               { Console.Error.WriteLine($"Error: {ex.Message}"); }
    }
}

