        string stampPath  = "stamp.png";
        string outputPath = "output.pdf";

        if (!File.Exists(inputPath)) { Console.Error.WriteLine($"File not found: {inputPath}"); return; }
        if (!File.Exists(stampPath)) { Console.Error.WriteLine($"Stamp image not found: {stampPath}"); return; }

        using (Document pdfDocument = new Document(inputPath))
        {
            ImageStamp imgStamp = new ImageStamp(stampPath);
            imgStamp.Background          = false;
            imgStamp.Opacity             = 0.5;
            imgStamp.HorizontalAlignment = HorizontalAlignment.Center;
            imgStamp.VerticalAlignment   = VerticalAlignment.Center;

            // CORRECT: call AddStamp on each individual Page
            foreach (Page page in pdfDocument.Pages)
            {
                page.AddStamp(imgStamp);
            }

            pdfDocument.Save(outputPath);
        }

        Console.WriteLine($"Image stamp applied to all pages, saved to '{outputPath}'.");
    }
}

